arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Changed from Singleton to Scoped: CacheService captures scoped IUserService.
// .NET 9 enables ValidateScopes/ValidateOnBuild by default, making the
// previous singleton registration throw at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// ConfigureHttpMessageHandlerBuilder was removed in .NET 9.
// The default primary handler is now SocketsHttpHandler (not HttpClientHandler).
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
    {
        return new SocketsHttpHandler { UseCookies = false };
    });
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
var app = builder.Build();
app.UseForwardedHeaders();
// .NET 9 removed Trace-level request header logging from Kestrel.
// Use the HTTP logging middleware with explicit header fields instead.
app.UseHttpLogging();
app.Run();

